package com.mindskip.xzs.test;

import com.mindskip.xzs.utility.RsaUtil;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;

public class TestRsaAndBCrypt {

    public static void main(String[] args) {
        String privateKey = "";
        String encryptedPwd = "D1AGFL+Gx37t0NPG4d6biYP5Z31cNbwhK5w1lUeiHB2zagqbk8efYfSjYoh1Z/j1dkiRjHU+b0EpwzCh8IGsksJjzD65ci5LsnodQVf4Uj6D3pwoscXGqmkjjpzvSJbx42swwNTA+QoDU8YLo7JhtbUK2X0qCjFGpd+8eJ5BGvk=";

        System.out.println("=== RSA解密测试 ===");
        String decryptedPwd = RsaUtil.rsaDecode(privateKey, encryptedPwd);
        System.out.println("解密后的密码: " + decryptedPwd);

        if (decryptedPwd != null) {
            System.out.println("\n=== BCrypt生成 ===");
            BCryptPasswordEncoder encoder = new BCryptPasswordEncoder();
            String bcryptPwd = encoder.encode(decryptedPwd);
            System.out.println("BCrypt格式: " + bcryptPwd);
            
            System.out.println("\n=== 验证 ===");
            System.out.println("解密后密码与'123456'匹配: " + decryptedPwd.equals("123456"));
        }
    }
}
